insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('30618', 'i.bu', 'ibu', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"wanita yang telah melahirkan seseorang; ibung; ina; inang; mak","contoh":[{"nomor":2,"teks":"anak harus menyayangi --"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kata sapaan untuk wanita yang sudah bersuami","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"sapaan takzim kepada perempuan, baik yang sudah bersuami maupun yang belum","contoh":[]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian yang pokok (besar, asal, dan sebagainya)","contoh":[{"nomor":2,"teks":"-- jari"}]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"hal yang utama di antara beberapa hal lain; hal terpenting","contoh":[{"nomor":2,"teks":"-- negeri"},{"nomor":4,"teks":"-- kota"}]},{"nomor":"6","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"orang tua perempuan","contoh":[]}]', null, '["beribu","beribu-bapak","keibuan","peribuan"]', '["ibu akar","ibu angkat","ibu asuh","ibu ayam","ibu bangsa","ibu bapak","ibu baptis","ibu canang","ibu jari","ibu kaki","ibu kandung","ibu kos","ibu kota","ibu kota kabupaten","ibu kota kecamatan","ibu kota madya","ibu kota negara","ibu kota provinsi","ibu negara","ibu negeri","ibu papan","ibu pasir","ibu pengganti","ibu peri","ibu permandian","ibu pertiwi","ibu pungut","ibu rumah tangga","ibu sambung","ibu siaga","ibu sungai","ibu suri","ibu susu","ibu susuan","ibu tangan","ibu tangga","ibu tangkai daun","ibu tiri"]', '["kalau ibu kaya, anak jadi putri, kalau anak kaya, ibu jadi budak","kasih ibu sepanjang jalan, kasih anak sepanjang penggalan","kecil dikandung ibu, besar dikandung adat, mati dikandung tanah"]', '["bapak angkasa, ibu pertiwi"]', '[{"peribahasa":"kalau ibu kaya, anak jadi putri, kalau anak kaya, ibu jadi budak","makna":"Peribahasa ini menggambarkan perbedaan perlakuan dan tanggung jawab antara ibu dan anak. Ketika ibu memiliki harta, anaknya akan hidup senang layaknya seorang putri. Sebaliknya, jika anak yang menjadi kaya, sering kali ibunya justru diperlakukan seperti pembantu atau orang yang harus terus melayani."},{"peribahasa":"kasih ibu sepanjang jalan, kasih anak sepanjang penggalan","makna":"Peribahasa ini bermakna bahwa kasih sayang seorang ibu kepada anaknya tidak terbatas, tulus, dan abadi, sedangkan kasih sayang anak kepada ibunya sering kali terbatas atau mudah dilupakan."},{"peribahasa":"kecil dikandung ibu, besar dikandung adat, mati dikandung tanah","makna":"Peribahasa ini menggambarkan tiga fase penting dalam kehidupan manusia. Saat kecil, seseorang berada dalam lindungan dan tanggung jawab ibunya. Setelah dewasa, ia harus hidup sesuai dengan norma dan aturan adat yang berlaku di masyarakatnya. Pada akhirnya, setelah meninggal dunia, ia akan kembali ke tanah."}]');
