insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('30812', 'i.kan', 'ikan', '', '', '["Nomina","Nomina","Cakapan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"vertebrata yang hidup dalam air, berdarah dingin, umumnya bernapas dengan insang, tubuhnya biasanya bersisik, bergerak dan menjaga keseimbangan badannya dengan menggunakan sirip","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"lauk","contoh":[{"nomor":2,"teks":"makan nasi --nya tempe"}]}]', null, '["berikan","ikanan","pengikan","perikanan"]', '["ikan abisal","ikan adfluvial","ikan adu siam","ikan air tawar","ikan alu","ikan anadrom fluvial","ikan anadrom lakustrin","ikan ancu","ikan arapaima","ikan asap","ikan asin","ikan babi","ikan badut","ikan bakar","ikan basah","ikan batipelagis","ikan batu","ikan bedukang","ikan beku","ikan belalang","ikan beliung","ikan belukang","ikan bembam","ikan bentik","ikan bersirip","ikan biawan","ikan bidadari","ikan biji nangka","ikan biru","ikan boto-boto","ikan buas","ikan bulalao","ikan bulan","ikan bungkus","ikan bungo","ikan busuk","ikan buta muna","ikan capelin","ikan capung","ikan capungan banggai","ikan cue","ikan darat","ikan dasar","ikan demersal","ikan dokter","ikan duri","ikan eksotik","ikan emas","ikan emas pamarasan","ikan fluvial","ikan forare","ikan fosil hidup","ikan gajah","ikan glodok","ikan gobi belirik","ikan graskap","ikan gurita","ikan herbivor","ikan hias","ikan hibrida","ikan japuh","ikan jarang gigi","ikan jenggi","ikan kambing","ikan kambing matahari","ikan kancera domas","ikan kapas","ikan kapindang","ikan karang","ikan kawal","ikan kawan","ikan kayu","ikan keli","ikan kena tuba","ikan kepala batu","ikan kepala timah","ikan kering","ikan kodok maluku","ikan koki","ikan kutuk","ikan kuwe hitam","ikan laga","ikan lakustrin","ikan laut","ikan layak","ikan layang","ikan layang anggur","ikan layang benggol","ikan layang biru","ikan layang lidi","ikan lepu batu karang","ikan lidi","ikan lodan","ikan lou han","ikan lumba-lumba","ikan makanan","ikan mambo buntal","ikan mandarin","ikan mangsi","ikan matang","ikan merakar","ikan mua","ikan muara","ikan napoleon","ikan nil","ikan nila","ikan olahan","ikan ole","ikan oseani","ikan ovipar","ikan ovovivipar","ikan pantai","ikan panting","ikan paru-paru","ikan paus","ikan peda","ikan pedang","ikan pekasam","ikan pelagik","ikan pelangi","ikan pemanah","ikan pipih","ikan pogot","ikan puput","ikan raja laut","ikan rucah","ikan salai","ikan salem","ikan sarak","ikan sebelah","ikan segar","ikan semah","ikan sembilang","ikan serdadu","ikan setan","ikan setoka","ikan sia","ikan sia-sia","ikan singa","ikan skorpion","ikan sturgeon","ikan sumpit","ikan sungai","ikan tambakan","ikan tamban","ikan telur","ikan temenggung","ikan tepi","ikan terbang","ikan terubuk","ikan vivipar","perikanan rakyat","perikanan tangkap"]', '["ada air ada ikan","ada nyawa, ada ikan","asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","bagai ikan dalam keroncong","bagai ikan kena tuba","bondong air, bondong ikan","gula di mulut, ikan dalam belanga","hendak menangguk ikan, tertangguk batang","hilang ikan dalam kerabu","ikan belum dapat, airnya sudah keruh","ikan biar dapat, serampang jangan pokah","ikan biar dapat, serampang jangan pukah","ikan busuk mulai dari kepala","ikan di hulu, tuba di hilir","ikan di laut, asam di gunung, bertemu dalam belanga","ikan gantung, kucing tunggu","ikan lagi di laut, lada garam sudah dalam sengkalan","ikan pulang ke lubuk","ikan seekor rusakkan ikan setajau","ikan sekambu rusak oleh ikan seekor","ikan terkilat, jala tiba","kalau menyeberang sungai, biarlah ditelan oleh buaya, tetapi jangan dipagut oleh ikan kecil","kuat ikan karena radai (kuat burung karena sayap, kuat ketam karena sepit)","kuat ketam karena sepit, kuat burung karena sayap, kuat ikan karena radai","mati ikan karena umpan, mati sahaya karena budi","pukat terlabuh, ikan tak dapat","pusat jala pumpunan ikan","seperti ikan kena tuba","seperti ikan baung dekat pemandian","seperti ikan dalam air","seperti ikan dalam belat","seperti ikan dalam tebat","seperti menangkap ikan dalam belanga","sungguhpun kawat yang dibentuk, ikan di laut yang diadang","tertangkap di ikan kalang","tuba habis, ikan tak dapat","udang hendak mengatai ikan","ular bukan, ikan pun bukan","umpan habis, ikan tak kena"]', '[]', '[{"peribahasa":"ada air ada ikan","makna":"Peribahasa ini bermakna bahwa di mana pun kita tinggal atau berada, rezeki pasti akan selalu ada."},{"peribahasa":"ada nyawa, ada ikan","makna":"Peribahasa ini mengandung arti bahwa selama masih hidup, seseorang akan terus berusaha dan berikhtiar untuk mencari rezeki atau penghidupan."},{"peribahasa":"asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","makna":"Peribahasa ini menggambarkan bahwa meskipun berasal dari tempat yang berbeda atau berjauhan, jika sudah jodoh, pada akhirnya akan bertemu juga."},{"peribahasa":"bagai ikan dalam keroncong","makna":"Peribahasa ini melukiskan keadaan seseorang yang berada dalam kesulitan besar atau situasi yang sangat sempit dan tidak berdaya."},{"peribahasa":"bagai ikan kena tuba","makna":"Peribahasa ini menggambarkan sekelompok orang yang bingung, tidak berdaya, atau menderita akibat suatu musibah atau kejadian yang menimpa mereka secara tiba-tiba."},{"peribahasa":"bondong air, bondong ikan","makna":"Peribahasa ini bermakna bahwa di mana ada keramaian atau banyak orang berkumpul, di situlah biasanya rezeki atau keuntungan lebih mudah didapat."},{"peribahasa":"gula di mulut, ikan dalam belanga","makna":"Peribahasa ini menggambarkan seseorang yang pandai berkata-kata manis dan menjanjikan sesuatu yang indah, padahal dalam hatinya memiliki maksud tersembunyi atau niat buruk untuk mengambil keuntungan."},{"peribahasa":"hendak menangguk ikan, tertangguk batang","makna":"Peribahasa ini berarti bahwa seseorang yang mengharapkan keuntungan atau hasil yang baik, tetapi justru mendapatkan kerugian atau kekecewaan."},{"peribahasa":"hilang ikan dalam kerabu","makna":"Peribahasa ini menggambarkan hilangnya sesuatu yang berharga atau penting di tengah-tengah keramaian atau kekacauan, sehingga sulit untuk ditemukan kembali."},{"peribahasa":"ikan belum dapat, airnya sudah keruh","makna":"Peribahasa ini bermakna bahwa suatu rencana atau usaha sudah gagal sebelum dimulai karena persiapan yang keliru atau tindakan yang terburu-buru sehingga menimbulkan masalah."},{"peribahasa":"ikan biar dapat, serampang jangan pokah","makna":"Peribahasa ini mengandung arti bahwa dalam mencapai suatu tujuan, hendaknya dilakukan dengan cara yang bijaksana dan cermat agar tidak merusak sarana atau alat yang digunakan."},{"peribahasa":"ikan biar dapat, serampang jangan pukah","makna":"Peribahasa ini memiliki makna yang sama dengan \"ikan biar dapat, serampang jangan pokah\", yaitu dalam mencapai suatu tujuan, hendaknya dilakukan dengan cara yang bijaksana dan cermat agar tidak merusak sarana atau alat yang digunakan."},{"peribahasa":"ikan busuk mulai dari kepala","makna":"Peribahasa ini bermakna bahwa kerusakan atau kebobrokan dalam suatu organisasi, kelompok, atau negara biasanya berasal dari para pemimpinnya."},{"peribahasa":"ikan di hulu, tuba di hilir","makna":"Peribahasa ini menggambarkan suatu perbuatan yang sia-sia atau tidak akan membawa hasil karena dilakukan dengan cara yang salah atau tidak pada tempatnya."},{"peribahasa":"ikan di laut, asam di gunung, bertemu dalam belanga","makna":"Peribahasa ini menggambarkan bahwa meskipun berasal dari tempat yang berbeda atau berjauhan, jika sudah jodoh, pada akhirnya akan bertemu juga."},{"peribahasa":"ikan gantung, kucing tunggu","makna":"Peribahasa ini melukiskan keadaan di mana seseorang dihadapkan pada godaan besar yang sulit untuk dihindari, atau seseorang yang mengharapkan sesuatu yang mustahil didapat."},{"peribahasa":"ikan lagi di laut, lada garam sudah dalam sengkalan","makna":"Peribahasa ini menggambarkan seseorang yang sudah bersiap-siap untuk merayakan atau menikmati sesuatu yang belum pasti diperoleh."},{"peribahasa":"ikan pulang ke lubuk","makna":"Peribahasa ini bermakna bahwa seseorang telah kembali ke tempat asalnya atau lingkungan yang paling sesuai baginya."},{"peribahasa":"ikan seekor rusakkan ikan setajau","makna":"Peribahasa ini berarti bahwa karena kesalahan atau keburukan satu orang, seluruh kelompok atau komunitas menjadi ikut tercemar nama baiknya."},{"peribahasa":"ikan sekambu rusak oleh ikan seekor","makna":"Peribahasa ini memiliki makna yang sama dengan \"ikan seekor rusakkan ikan setajau\", yaitu karena kesalahan atau keburukan satu orang, seluruh kelompok atau komunitas menjadi ikut tercemar nama baiknya."},{"peribahasa":"ikan terkilat, jala tiba","makna":"Peribahasa ini menggambarkan kecepatan dan ketepatan dalam bertindak. Seseorang yang cerdik dan tanggap akan segera memahami maksud atau tujuan orang lain hanya dari isyarat kecil, dan langsung mengambil tindakan yang diperlukan."},{"peribahasa":"kalau menyeberang sungai, biarlah ditelan oleh buaya, tetapi jangan dipagut oleh ikan kecil","makna":"Peribahasa ini bermakna bahwa lebih baik mati atau kalah karena melawan musuh yang besar dan kuat daripada mati atau kalah karena hal-hal sepele atau musuh yang lemah."},{"peribahasa":"kuat ikan karena radai (kuat burung karena sayap, kuat ketam karena sepit)","makna":"Peribahasa ini mengandung arti bahwa setiap makhluk memiliki kekuatan atau kelebihannya masing-masing yang sesuai dengan kodratnya."},{"peribahasa":"kuat ketam karena sepit, kuat burung karena sayap, kuat ikan karena radai","makna":"Peribahasa ini memiliki makna yang sama dengan \"kuat ikan karena radai (kuat burung karena sayap, kuat ketam karena sepit)\", yaitu setiap makhluk memiliki kekuatan atau kelebihannya masing-masing yang sesuai dengan kodratnya."},{"peribahasa":"mati ikan karena umpan, mati sahaya karena budi","makna":"Peribahasa ini bermakna bahwa seseorang dapat terjerat atau celaka karena bujukan atau iming-iming (umpan), tetapi juga dapat terikat atau takluk karena kebaikan hati dan perlakuan yang baik (budi)."},{"peribahasa":"pukat terlabuh, ikan tak dapat","makna":"Peribahasa ini menggambarkan suatu usaha atau pekerjaan yang telah dilakukan dengan susah payah, tetapi pada akhirnya tidak membuahkan hasil sama sekali."},{"peribahasa":"pusat jala pumpunan ikan","makna":"Peribahasa ini bermakna bahwa suatu tempat yang menjadi pusat kegiatan atau berkumpulnya banyak orang biasanya juga menjadi pusat rezeki atau keuntungan."},{"peribahasa":"seperti ikan kena tuba","makna":"Peribahasa ini menggambarkan sekelompok orang yang bingung, tidak berdaya, atau menderita akibat suatu musibah atau kejadian yang menimpa mereka secara tiba-tiba."},{"peribahasa":"seperti ikan baung dekat pemandian","makna":"Peribahasa ini menggambarkan seseorang yang selalu waspada dan siap siaga terhadap bahaya yang mungkin datang."},{"peribahasa":"seperti ikan dalam air","makna":"Peribahasa ini melukiskan perasaan seseorang yang sangat senang dan bahagia karena berada di lingkungan yang sangat disukainya atau sesuai dengan keinginannya."},{"peribahasa":"seperti ikan dalam belat","makna":"Peribahasa ini menggambarkan keadaan seseorang yang terperangkap dalam suatu situasi yang sulit dan tidak memiliki jalan keluar."},{"peribahasa":"seperti ikan dalam tebat","makna":"Peribahasa ini menggambarkan seseorang yang hidup dalam kesenangan dan kemudahan, tanpa ada kesulitan atau gangguan."},{"peribahasa":"seperti menangkap ikan dalam belanga","makna":"Peribahasa ini menggambarkan suatu pekerjaan yang sangat mudah dilakukan atau keuntungan yang sudah pasti akan didapat."},{"peribahasa":"sungguhpun kawat yang dibentuk, ikan di laut yang diadang","makna":"Peribahasa ini bermakna bahwa meskipun yang terlihat adalah suatu perbuatan atau usaha yang sederhana, sebenarnya tujuannya adalah untuk mencapai sesuatu yang jauh lebih besar dan berharga."},{"peribahasa":"tertangkap di ikan kalang","makna":"Peribahasa ini berarti tertangkap basah saat melakukan suatu kejahatan atau perbuatan tercela."},{"peribahasa":"tuba habis, ikan tak dapat","makna":"Peribahasa ini menggambarkan suatu usaha yang sia-sia dan merugikan, di mana modal atau sumber daya sudah habis terpakai, tetapi hasilnya tidak ada sama sekali."},{"peribahasa":"udang hendak mengatai ikan","makna":"Peribahasa ini menyindir seseorang yang mencela atau mengkritik orang lain, padahal dirinya sendiri memiliki kekurangan atau kesalahan yang sama, bahkan lebih buruk."},{"peribahasa":"ular bukan, ikan pun bukan","makna":"Peribahasa ini menggambarkan sesuatu yang tidak jelas atau tidak memiliki kepastian, sehingga sulit untuk digolongkan atau dinilai."},{"peribahasa":"umpan habis, ikan tak kena","makna":"Peribahasa ini bermakna bahwa usaha yang dilakukan telah menghabiskan banyak biaya atau tenaga, tetapi tidak membuahkan hasil yang diharapkan."}]');
