insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('31493', 'i.nai', 'inai', '', '', '["Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"perdu yang tumbuh tegak, tinggi hingga 4 m, banyak ditanam karena daun dan bunganya yang wangi, daunnya dijadikan pemerah kuku; pacar〔Lawsonia inermis〕","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"daun inai","contoh":[]}]', '{"text":"[Persia حنائی ḥināʼī a ''berkaitan dengan tumbuhan yang daunnya untuk melukis tangan'']","languages":["Persia"]}', '["berinai","menginai"]', '["inai curi","inai lebai","inai tengah"]', '["bagai inai dengan kuku","inai tertepung, kuku tanggal","kaki teracung inai obatnya, mulut terlanjur emas dendanya","kaki tertarung, inai padahannya (mulut terdorong, emas padahannya)"]', '[]', '[{"peribahasa":"bagai inai dengan kuku","makna":"Peribahasa ini menggambarkan hubungan yang sangat erat, akrab, dan tidak dapat dipisahkan antara dua orang sahabat."},{"peribahasa":"inai tertepung, kuku tanggal","makna":"Peribahasa ini bermakna bahwa setelah suatu pekerjaan atau usaha selesai, alat atau sarana yang digunakan untuk menyelesaikannya sudah tidak diperlukan lagi."},{"peribahasa":"kaki teracung inai obatnya, mulut terlanjur emas dendanya","makna":"Peribahasa ini menasihatkan bahwa setiap perbuatan atau perkataan akan ada akibatnya. Jika kaki terluka, obatnya adalah inai (pengobatan sederhana). Namun, jika mulut salah berucap, akibatnya bisa sangat besar dan mahal (denda emas)."},{"peribahasa":"kaki tertarung, inai padahannya (mulut terdorong, emas padahannya)","makna":"Peribahasa ini memiliki makna yang serupa dengan \"kaki teracung inai obatnya, mulut terlanjur emas dendanya\", yaitu setiap perbuatan atau perkataan akan ada akibatnya. Kesalahan kecil (kaki tertarung) dapat diperbaiki dengan mudah (inai), tetapi kesalahan besar dalam perkataan (mulut terdorong) akan mendatangkan akibat yang berat (emas padahannya)."}]');
